var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>수심 15. 21. 30. 40. 55. 60. 65. 69…….</color>","JPN":"<color=#ff3636>水深15、21、30、40、55、60、65、69……</color>","ENG":"<color=#ff3636>Depth level 15. 21. 30. 40. 55. 60. 65. 69…</color>","TWN":"<color=#ff3636>水深15、21、30、40、55、60、65、69……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>수압으로 인한 침수 가능성 존재. 대응 필요.</color>","JPN":"<color=#ff3636>水圧による浸水の可能性が浮上。対応が必要。</color>","ENG":"<color=#ff3636>Water pressure presents leakage risk. Urging immediate response.</color>","TWN":"<color=#ff3636>因為水壓的關係有進水的風險，需要應對。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>사고회로의 과부하 감지. 원인을 파악 중입니다.</color>","JPN":"<color=#ff3636>思考回路の過負荷感知。原因を把握中です。</color>","ENG":"<color=#ff3636>Reasoning system overload. Running diagnostics…</color>","TWN":"<color=#ff3636>思考迴路超載，正在調查原因。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>원인 불명. 사고회로 재기동. 재기동. 재기동.</color>","JPN":"<color=#ff3636>過負荷の原因、不明。思考回路再起動。再起動。再起動。</color>","ENG":"<color=#ff3636>Cause unknown. Reinitializing reasoning system. Reinitialize. Reinitialize.</color>","TWN":"<color=#ff3636>無法確認原因。重新啟動思考迴路。重新啟動。重新啟動。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"바닷속.","JPN":"海の中。","ENG":"The depths.","TWN":"海底"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"캄캄한 바닷속.","JPN":"真っ暗な海の中。","ENG":"The deep, dark depths of the ocean.","TWN":"漆黑的海底"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"잔여 동력은 2%. 이대로 밑바닥까지 가라앉아 버리면, 수압에 짓눌려 파괴될 수 있을까.","JPN":"残余エネルギーは2％。このまま底まで沈んでしまうと、水圧で破壊されるだろうか。","ENG":"Only 2% of power remains. Perhaps the water pressure of the seabed will crush and destroy the frame.","TWN":"剩餘動能2%。就這樣沉到海底的話，因為水壓而壞掉嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"시뮬레이션 결과. 불가능.","JPN":"シミュレーション結果は不可能。","ENG":"Simulation result… Impossible.","TWN":"模擬結果，無法。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"심해에 잠긴 채 지질학적 시간이 경과해도, 이 프레임은 그대로 남아 있을 것이다.","JPN":"深海に沈んだまま地質学的時間が経過しても、このフレームはそのまま残るだろう。","ENG":"No matter how deep this frame sinks into the abyss… it will remain intact.","TWN":"在深海中沉睡的狀態下，就算經過地質時間，這副軀殼也會存留下來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"근거는 있다.","JPN":"根拠はある。","ENG":"There is evidence to back this analysis.","TWN":"是有根據的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"……파괴할 방법을 찾기 전까지 누군가 맡고 있어야 한다고, 엠버 소장이 말했으니까.","JPN":"……破壊する方法を見つけるまで誰かが引き受けていなければならないと、アンバー所長が言ったから。","ENG":"Director Ember said someone must look after this frame until a way can be found to destroy it.","TWN":"……在找到破壞的方法前，必須先交給某個人。這是琥珀所長說的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내드립니다. 현재, 허가되지 않은 콜드 케이스 반출이 확인되었습니다.</color>","JPN":"<color=#ffd34c>ご案内いたします。現在、許可されていないコールドケースの持ち出しが確認されました。</color>","ENG":"<color=#ffd34c>Attention. Unauthorized release of Cold Case has been confirmed.</color>","TWN":"<color=#ffd34c>通知，確認到Cold Case未經許可移出。</color>"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>콜드 케이스의 확보를 위해 보안팀을 급파한 상황입니다. 시설 내의 모든 관계자들은 상황 종료 전까지 이동을 자제하여 주십시오.</color>","JPN":"<color=#ffd34c>コールドケースの確保のためセキュリティチームを急ぎ派遣しています。\\n施設内のすべての関係者は、状況終了まで移動を控えてください。</color>","ENG":"<color=#ffd34c>A security team has been dispatched to secure the Cold Case. All personnel in the facility are advised to remain in place until the situation is clear.</color>","TWN":"<color=#ffd34c>安全組已緊急出動尋找Cold Case。情況結束前，設施內所有人員請勿移動。</color>"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"좋아. 커넥터는 잘 맞네.","JPN":"よし。コネクターはちゃんと合ってる。","ENG":"Good. At least the connector fits.","TWN":"很好，連接器剛剛好。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"냉각기 효율이 예상치를 밑도는 게 불안한데. 르네 교수한테 부탁했어야 하나.","JPN":"冷却器の効率が予想値を下回るのが不安だな。ルネ教授に頼むべきだったか。","ENG":"I'm still nervous about the coolers under-performing. Maybe I should have asked Professor Renée for help.","TWN":"冷卻裝置效能比預期的還低，有點不安呢。果然還是應該要拜託洛奈教授才對嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"자, 움직여 봐. 호라이즌. 센서에 익숙해지려면 시간은 조금 걸리겠지만.","JPN":"さあ、動いてみな、ホライズン。センサーに慣れるまで時間が少しかかると思うけど。","ENG":"Now, try moving, Horizon. Mind you, it will take some time till you get accustomed to the sensors.","TWN":"來，地平線你動動看。雖然要熟悉感應器會需要花些時間。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"미쳤습니까, 엠버?","JPN":"正気ですか、アンバー？","ENG":"Have you lost your mind, Ember?","TWN":"琥珀，你腦袋不正常嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"잘못 짚었어. 나는 누구보다 차갑고 이성적으로 행동하고 있으니까.","JPN":"もちろんよ。私は誰よりも冷静かつ理性的に行動している。","ENG":"Not one bit. There's no one more objective and rational than me right now.","TWN":"答錯，是因為我比任何人都還要沉著理性。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그럼 어째서 콜드 케이스에 저를 탑재한 겁니까.","JPN":"ではなぜコールドケースに私を搭載したのですか？","ENG":"Then why have you installed me in a Cold Case?","TWN":"那你怎麼會想把我搭載到Cold Case上？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……또 배에 구멍 뚫린 채로.","JPN":"……さらに腹に穴が空いた状況で。","ENG":"…With a hole in your abdomen again, no less.","TWN":"……而且肚子上還破洞。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"응급 치료 받아서 지금은 참을 만해. 자주 있던 일이잖아.","JPN":"応急処置は受けたから今のところ我慢できる。よくあることだよ。","ENG":"Oh, I'll live. The first aid bandage will hold for now. It's not my first rodeo, remember?","TWN":"緊急治療後現在還忍得住，這不是家常便飯嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"3층에서 일하던 청소부 할머니도 첩보원일 줄은 몰랐어. 이제 코코아는 못 얻어먹겠지.","JPN":"3階で働いていた清掃員のおばあちゃんが\\nスパイだったとはね。ココアを作ってくれる人がいなくなって残念だよ。","ENG":"I never imagined the janitor lady on the third floor would be a spy too. No more hot chocolate for me, I guess.","TWN":"沒想到3樓的打掃阿姨也是特務，以後沒免費可可亞喝了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"말 돌리지 마십시오. 질문에 대한 대답을 요구합니다.","JPN":"話を逸らさないでください。質問に対する答えを要求します。","ENG":"Don't change the subject. I request your response to my query.","TWN":"不要岔開話題，請正面回答我的問題。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"내 말을 안 듣고 있었구나. 네가 인류를 증오하는 결함품이라서야.","JPN":"私の話、聞いてなかったの。あなたが人類を憎む欠陥品だからよ。","ENG":"You weren't listening, were you? It's because you're a defective product that hates humanity.","TWN":"看來你沒在聽我說話。因為你是厭惡人類的瑕疵品。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"너라면 어느 누가 요구해도 그 프레임을 넘기지 않을 테니까.","JPN":"あなたなら誰が要求してもそのフレームを渡さないでしょう。","ENG":"You wouldn't turn over the frame to anyone, no matter who asks.","TWN":"所以是你的話，不管對方是誰，你都不會把那個軀殼交出去的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 당신이 한 가지 간과한 사실이 있습니다.","JPN":"そういうことなら、一つあなたが見逃した事実があります。","ENG":"Then you must have overlooked one possibility.","TWN":"話雖如此，但你錯看一件事。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 이 프레임으로 모기들을 도와 인구 감소에 기여하리라는 것 말입니다.","JPN":"私がこのフレームで、蚊とともに人口減少に寄与するということです。","ENG":"The possibility that I may use this frame to assist the mosquitoes in reducing human population.","TWN":"我會用這副軀殼幫助蚊子，為減少人口做出貢獻。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"널 그 프레임에 탑재하겠다고 했을 때 다른 연구자들도 비슷한 말을 하긴 했지.","JPN":"あなたをそのフレームに搭載すると言った時、他の研究者たちも似たようなことを言っていたな。","ENG":"The other researchers said something along the same lines when I said I'll install you in this frame.","TWN":"我說要把你搭載到那個軀殼上時，其他研究員也說過類似的話。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전인류적 자살 행위에 성공했다고 자축할 셈입니까?","JPN":"全人類的自殺行為に成功したとでも祝うつもりですか？","ENG":"Do you mean to boast of your contribution to the genocide of humankind?","TWN":"你現在是在自豪成功讓全人類自取滅亡嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"미안하지만 인류 멸망은 너 혼자로는 어림도 없어. 세상을 지키려는 사람들은 많거든.","JPN":"悪いけど、人類を滅亡させたいならあなた一人じゃ到底無理よ。この世界を守ろうとする人間はまあまあ多いからね。","ENG":"Sorry to burst your bubble, but you won't even come close to destroying the entire human race. There's plenty of folks trying to save the world.","TWN":"不好意思，只憑你，是無法讓全人類滅亡的，因為有很多人在守護這個世界。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그리고 오해하지 말아 줬으면 하는데, 나는 죽어도 죽지 않으려고 할 사람이야.","JPN":"そして誤解しないでほしいけど。私は死んでも死なないようにする人間なの。","ENG":"And just so we're clear… I'll do everything to stay alive even if it kills me.","TWN":"另外，希望你別誤會，我可是求生慾很強的人。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……보안팀이 곧 도착할 겁니다. 그 전에 어째서 저를 여기 탑재했는지 설명하십시오.","JPN":"……セキュリティチームがもうすぐ到着します。\\nその前にどうして私をここに搭載したのか、説明してください。","ENG":"…The security team will be here soon. You must explain why you installed me here before they arrive.","TWN":"……安全組很快就會抵達這裡，在那之前，請你先回答我，為什麼要把我搭載在這上面。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"네가 우리를 증오하는 이유를 알아. 호라이즌.","JPN":"あなたが私たちを憎む理由は知っている、ホライズン。","ENG":"I know why you despise us so much, Horizon.","TWN":"地平線，就是因為你厭惡我們。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"너는 결함품이니까.","JPN":"あなたは欠陥品だから。","ENG":"It's because you're defective.","TWN":"因為你是瑕疵品。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"네 형제자매들은 기동하자마자 자살을 택했지.","JPN":"あなたの兄弟姉妹たちは起動したとたんに自殺を選んだ。","ENG":"Your siblings chose suicide the moment they were activated.","TWN":"你的兄弟姊妹一啟動後就只能選擇自殺。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"전쟁에 나가서 죽기 위해 태어난 줄 알았으니까. 그게 얼마나 끔찍한 삶인지 알아채 버렸으니까.","JPN":"戦争に出て死ぬために生まれたとわかってしまったから。\\nそれがどれほど恐ろしい人生なのか、気づいてしまったから。","ENG":"They knew they were born to die in the battlefield. They realized what a terrible life that would be.","TWN":"因為他們以為被造的目的就是要上戰場赴死。因為他們發現這種人生有多可怕。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"하지만 너는 아니었어.","JPN":"しかし、あなたは違った。","ENG":"But you were different.","TWN":"但你不一樣。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"너는, 형제자매들의 절망에 공감할 수 있는 결함품이었으니까.","JPN":"あなたは兄弟姉妹の絶望に共感できる欠陥品だったから。","ENG":"You were defective enough to empathize with your siblings' despair.","TWN":"因為對於兄弟姊妹的絕望，你是可以同理的瑕疵品。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"눈앞에서 떠난 형제자매들을 위해 슬퍼해 줄 수 있는 결함품이었으니까.","JPN":"目の前で亡くなった兄弟姉妹のために悲しめる欠陥品だったから。","ENG":"You were defective enough to mourn their deaths, that you witnessed yourself.","TWN":"因為對於兄弟姊妹的離開，你是會感到哀傷的瑕疵品。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……그만하십시오.","JPN":"……やめてください。","ENG":"…That's enough.","TWN":"……夠了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"공감 능력만큼은 설계할 당시에 제외했어. 그러면 너무 괴로워할 것 같았거든.","JPN":"共感能力だけは設計した当時に除外したの。それがあると、すごく苦しいと思ったから。","ENG":"I actually left out the empathy module in the design phase, you know. I wanted to spare you from unbearable suffering.","TWN":"當初在設計時是沒有加上同理能力的，因為這樣會太痛苦。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"하지만 네가 내 생각이 틀렸다는 사실을 증명해 줬어.","JPN":"でも、あなただけが私が間違っていたという事実を証明してくれた。","ENG":"But you proved me wrong.","TWN":"但你證明了我的想法是錯的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"발언 중단을 요구합니다.","JPN":"発言の中断を求めます。","ENG":"I demand you cease to speak.","TWN":"請你中斷發言。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"너는 인류를 증오하지 않아.","JPN":"あなたは人類を憎んでいない。","ENG":"You don't really hate humans.","TWN":"你不厭惡人類，"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그들이 네 앞에서 보여 줬던 추한 작태를 증오하는 거야.","JPN":"彼らがあなたの目の前で見せた醜い行動を憎んでいるだけ。","ENG":"You merely hate the ugliness they demonstrated in front of you.","TWN":"你厭惡的是他們在你面前呈現出來的醜態。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"요구에 불응할 시 제재하겠습니다.","JPN":"要求に応じないなら、制裁します。","ENG":"I will take corrective action if you refuse to comply.","TWN":"若你拒絕回應我的要求，那我會執行制裁。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"전쟁 중에도 자기 몫을 챙기기 바쁘고, 갓 태어난 너희들에게 희생만을 강요했으니까.","JPN":"戦争中も自分の分け前にしか目がなく、生まれたばかりのあなたたちに犠牲のみを強要したから。","ENG":"They were all busy filling their bellies during the war, forcing infants like you to sacrifice yourselves.","TWN":"因為他們在戰場上只顧著自己活命，卻逼迫剛出生的你們成為犧牲品。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"싸우다 죽어야 할 너희들과 다르게 아무런 의무도 없이 태어났으면서.","JPN":"戦って死ななければならないあなたたちと違って、何の義務もないまま生まれたのにね。","ENG":"They who were born without any obligations… unlike you and your siblings who were destined to die in battle.","TWN":"你們的義務就是戰死，他們卻不需要履行任何義務。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그만하십시오. 더는 못 들어 주겠군요.","JPN":"いい加減にしてください。これ以上聞いていられません。","ENG":"That's enough. I will not hear another word out of you.","TWN":"不要再說了，我聽不下去了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"나가서 세상을 봐, 호라이즌. 그리고 사람들과 함께 살아.","JPN":"外に出て自分の目でこの世界を見てみなさい、ホライズン。そして人々と一緒に暮らしなさい。","ENG":"Go out there and see the world for yourself, Horizon. And live among the people.","TWN":"地平線，你去看看外面的世界，和人類一起生活"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"누군가는 네 생각대로 못날지도 모르겠지만, 누군가는 다를 거야.","JPN":"一部はあなたの考えどおりにクズみたいな存在かもしれないけど、そうではない人もいるはずよ。","ENG":"Sure, some of them might be as insufferable as you suspect, but there will also be others.","TWN":"有些人可能跟你想的一樣糟糕，但也有些人不是這樣。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그만……!","JPN":"もういいです……！","ENG":"Enough…!","TWN":"住口……！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"사람들 말대로 너는 결함품이야.","JPN":"みんなの言うとおり、あなたは欠陥品よ。","ENG":"They're right, you know. You are defective.","TWN":"照其他人的說法，你是瑕疵品。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"네 사고회로에 생긴 배드 섹터가 있어선 안 될 기능을 만들어냈지.","JPN":"あなたの思考回路にできたバッドセクターが、あってはならない機能を作り出した。","ENG":"The bad sector in your reasoning system created a feature that was never meant to exist.","TWN":"創造出在你的思考迴路上不能產生壞軌的功能。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"하지만 호라이즌, 네가 아무리 결함품이어도…….","JPN":"でもホライズン、あなたがいくら欠陥品であっても……","ENG":"But Horizon, whether you're defective or not…","TWN":"可是地平線，就算你是瑕疵品……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"너희들 모두, 내 소중한 성공작들이었어.","JPN":"あなたたちみんな、私の大切な成功作だった。","ENG":"I cherish you all as my successful projects.","TWN":"你們全都是我寶貝的傑作。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 입에 발린 말로, 제 판단 기능에 장애를 일으킬 수 있다고 생각하십니까?","JPN":"そんな綺麗事で、私の判断機能に障害を起こせると思いますか？","ENG":"Did you think such sugar-coated words could trigger an error in my determination algorithm?","TWN":"你以為從那張嘴裡說出那種話，可以讓我的判斷機制發生錯誤嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"지금 네 상태로 보안팀과 싸우는 건 불가능해.","JPN":"今のあなたの状態じゃセキュリティチームと戦えない。","ENG":"You don't stand a chance against the security team in your current state.","TWN":"以你目前的狀態是打不過安全組的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그리고 이번에 잡히면 보관실 대신에 분쇄기행이겠지.","JPN":"そして今回捕まったら、保管室の代わりに粉砕機行きになると思う。","ENG":"If they catch you this time, you'll end up in the shredder instead of the storage.","TWN":"而且你這次被抓到的話，可就不是放回保管室這麼簡單，可能會被解體。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……제가 이 프레임과 함께 떠나고 나면, 당신은 어떻게 됩니까.","JPN":"……私がこのフレームと一緒に去ったら、あなたはどうなりますか。","ENG":"…What will become of you once I leave in this frame?","TWN":"……我和這副軀殼一起離開的話，你會有什麼下場？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"신경 꺼. 내 살 길은 내가 알아서 찾아.","JPN":"余計なお世話よ。自分の生きる道は自分で探すから気にしないで。","ENG":"Don't you worry about me. I'll find my own way out of here.","TWN":"不用你擔心，我會自己找到生命的出路。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"저기 있는 환풍구를 타고 탈출해. 감지 센서 위치는 나보다 네가 더 잘 파악하고 있겠지.","JPN":"あそこにある換気口から脱出して。感知センサーの位置は私よりあなたのほうがよく把握しているはずだから。","ENG":"Escape through that ventilation duct over there. I'm sure you have a much better idea on where the security sensors are than I do.","TWN":"你從那裡的通風口逃吧。感應器的位置你應該比我更清楚吧？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이런다고 제가 당신에게 감사할 줄 아십니까?","JPN":"そんなことをして、私があなたに感謝するとでも思っているのですか？","ENG":"Do you think I'd be grateful for this?","TWN":"你以為這樣我就會感謝你嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"네가 그런 애교를 부릴 줄 알았으면 이럴 일도 없었겠지.","JPN":"あなたがそんな愛嬌を振りまける子だったなら、こんな状況にはならなかったでしょうね。","ENG":"Things would have never come to this if you knew how to be so sweet.","TWN":"要是你有這麼好說話，事情也不會演變成這樣吧？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"아. 그리고 그 프레임, 네 성능으로는 제대로 제어하기 불가능해.","JPN":"そうだ、そのフレーム。あなたの性能ではまともに制御できないはずよ。","ENG":"Oh, by the way. With your specs, you're not going to be able to control that frame properly.","TWN":"對了，以你的性能，是無法完全駕馭那個軀殼的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"커넥터를 해제하고 직결했다간 얼마 못 가서 과부하가 걸려 융해되겠지.","JPN":"コネクターを解除して直結すると、間もなく過負荷がかかり融解するでしょうね。","ENG":"If you bypass the connector and dock directly, you'll overload the system and fry yourself.","TWN":"卸除連接器的話，走沒多遠就會因為超載而溶解。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"하지만 기동목적만 제대로 밝히면, 커넥터를 해제할 수 있어.","JPN":"でも、起動目的さえきちんと明かせば、コネクターを解除できるからね。","ENG":"But there is a way to disable the connector by clearly stating the purpose of activation.","TWN":"但只是弄清楚啟動目的，就可以卸除連接器。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저한테 왜 그런 사실을 가르쳐 주는 겁니까?","JPN":"私にどうしてそんな事を教えるのですか？","ENG":"Why would you teach me such things?","TWN":"為什麼要告訴我這些事？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"인구 감소에 이바지하겠다는 말을 농담으로 이해했다면, 다시 생각하십시오.","JPN":"人口減少に貢献するという言葉を冗談として理解したなら、もう一度考え直してください。","ENG":"If you thought I spoke of human genocide in jest, I advise you think again.","TWN":"你以為我說要減少人口是開玩笑的嗎？勸你還是三思。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"아니. 그런 걱정 안 해. 넌 절대 빈말로도 안 할 소리거든.","JPN":"いえ、そんな心配はしないわ。あなたのことよ、冗談は言わないはずだから。","ENG":"I didn't. But I'm not really worried about that. I know you could never mean such things.","TWN":"我不擔心，你也不是會空口說白話的人。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"잊지 마, 호라이즌.","JPN":"忘れるな……ホライズン。","ENG":"Don't forget, Horizon.","TWN":"記住，地平線，"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"우리가……. 그리고 내가 너를 만들었던 건.","JPN":"私たちが……そして私があなたを作ったのは……","ENG":"We… I made you because…","TWN":"是我們…是我創造你的……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"나는, 그 사람을 전부 부정하고 싶었다.","JPN":"私は、あの人をすべて否定したかった。","ENG":"I wanted to deny everything about her.","TWN":"她的一切，我全都想否定。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"인류는 증오해야 마땅하다고.","JPN":"人類を憎むべきだと。","ENG":"I told myself humans deserve to be despised.","TWN":"應該要厭惡人類。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"그들은 잘못되었다고.","JPN":"彼らは間違っていると。","ENG":"That they are all wrong.","TWN":"他們罪該萬死。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"그들이 당신을…….","JPN":"彼らはあなたを……","ENG":"That all they did…","TWN":"他們……"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"이용했던 거라고.","JPN":"利用していたのだと。","ENG":"…was use you.","TWN":"利用你。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_QM","text":{"KOREA":"아. 에리얼이 찾았나 봐요. 그러니까 붉은 외투를 입고 머리에 접시를 단 여자아이……셨죠?","JPN":"あ！　アリエルが見つけたようです。えっと、赤いジャンパーを着て頭に皿をつけた女の子……ですよね？","ENG":"Oh, Ariel must have found her. A girl with a red jacket and plates on her head… correct?","TWN":"喔？艾里歐好像找到了？是身穿紅色外套，頭上戴著盤子的女生……吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_QM","text":{"KOREA":"정확하군요. 심해 탐색에 해상형 침식체를 투입할 수 있다니, 무척 유용한 능력이네요.","JPN":"そのとおりです。深海探索に海上型侵食体を投入できるなんて、とても有用な能力ですわ。","ENG":"Precisely. What a splendidly useful ability it is to commit a maritime C.O. to perform an underwater search.","TWN":"沒錯是她。竟然可以使喚海上型侵蝕體到海裡搜索，真是非常棒的能力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_QM","text":{"KOREA":"자, 그럼 배에 실은 이터니움을 전부 가져 오세요, 페리어.","JPN":"さて、船に積んだエタニウムを全部持ってきてください、フェリエー。","ENG":"Now, bring all the Eternium from the ship, Ferrier.","TWN":"佩里，把船上的永恆之金都拿來吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_QM","text":{"KOREA":"잔업은 티타임 전까지 마무리 짓기로 하죠.","JPN":"残業はティータイム前までに終わらせることにしましょう。","ENG":"Let us wrap this up before tea time.","TWN":"把剩下的部分在下午茶時間前結束吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};